import { Card, Text } from "@nextui-org/react";
import React from "react";
import star from "../Images/Star.svg";

export default function InfoCard(props: { subtitle: string; title: string }) {
  const ic = () => {
    return <img src={star} alt="Icon" />;
  };

  return (
    <Card
      isHoverable
      variant="bordered"
      css={{ mw: "250px", backgroundColor: "$purple600", margin: "auto" }}
    >
      <Card.Body css={{ ta: "center" }}>
        <>
          {ic}
          <Text h5>{props.title}</Text>
          <Text small css={{ mt: "5px" }}>
            {props.subtitle}
          </Text>
        </>
      </Card.Body>
    </Card>
  );
}
